import { useState, useEffect } from 'react';

import Navbar from "./front-end/components/Navbar";
import FakeLanding from "./front-end/components/FakeLanding";
import Home from "./front-end/pages/Home"
import Charts from "./front-end/pages/Charts";
import Stats from "./front-end/pages/Stats";

import { Typography, Box, Fade } from '@mui/material';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import CssBaseline from '@mui/material/CssBaseline';

import { Route, Routes } from 'react-router-dom';
import { text } from 'd3-request';
import { csvParseRows } from 'd3';
import listeningData from "./back-end/data/listening_data.csv";
// import url from "./data/book_data.csv";

function onlyUnique(value, index, array) {
  return array.indexOf(value) === index;
}

function App() {
  const darkTheme = createTheme({
    palette: {
      mode: 'light',
    },
    breakpoints: {
      values: {
        xs: 0,
        sm: 640,
        md: 960,
        lg: 1200,
        xl: 1536,
      },
    },
  });

  const [musicData, setMusicData] = useState([]);
  const [appLoaded, setAppLoaded] = useState(false);

  const [loading, setLoading] = useState(false);
  const [resultsLoaded, setResultsLoaded] = useState(false);

  useEffect(() => {
    text(listeningData, function(data) {
      var songData = csvParseRows(data).map((entry) => `${entry[1]} - ${entry[4]}`);
      var mappedSongData = songData.filter(onlyUnique);
      var artistData = csvParseRows(data).map((entry) => entry[4]);
      var mappedArtistData = artistData.filter(onlyUnique);
      var mappedData = [...mappedSongData, ...mappedArtistData]
      setMusicData(mappedData);
      setAppLoaded(true);
    })
  }, []);

  return (
    <ThemeProvider theme={darkTheme}>
      <CssBaseline />

      <Box sx = {{display: appLoaded ? "none" : "block"}}>
        <FakeLanding />
      </Box>

      <Fade in = {appLoaded} timeout={{ enter: 1500 }}>
        <Box sx = {{
          display: appLoaded ? "block" : "none",
        }}>
          <Navbar/>

          <Typography align = "center"  sx={{p: 3, typography: { md: 'h1', sm: 'h2', xs: 'h3' } }}>
            Erin's YT Music Data!
          </Typography>

          <Routes>
            <Route path="/" element={
              <Home 
                musicData = {musicData}
                loading = {loading}
                setLoading = {setLoading}
                resultsLoaded = {resultsLoaded}
                setResultsLoaded = {setResultsLoaded}
              />
            } />
            <Route path="/Charts" element={
              <Charts />
            } />
            <Route path="/Stats" element={
              <Stats />
            } />
          </Routes>
        </Box>
      </Fade>
    </ThemeProvider>
  );
}

export default App;